"use strict";(self.webpackChunkdeveloper_portal=self.webpackChunkdeveloper_portal||[]).push([["924"],{5226(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"category","label":"Introduction","collapsed":false,"items":[{"type":"link","href":"/product-overview","label":"Product Overview","docId":"product-overview","unlisted":false},{"type":"link","href":"/core-concepts","label":"Core Concepts","docId":"core-concepts","unlisted":false},{"type":"link","href":"/organization-onboarding","label":"Organization Onboarding","docId":"organization-onboarding","unlisted":false},{"type":"link","href":"/entity-and-root-ledger-model","label":"Entity & Root Ledger Model","docId":"entity-and-root-ledger-model","unlisted":false},{"type":"link","href":"/authentication-and-identity","label":"Authentication & Identity","docId":"authentication-and-identity","unlisted":false},{"type":"link","href":"/quickstart","label":"Quickstart","docId":"quickstart","unlisted":false},{"type":"link","href":"/actors-and-public-identity","label":"Actors & Public Identity","docId":"actors-and-public-identity","unlisted":false},{"type":"link","href":"/ledgers-and-traceledger-masters","label":"Ledgers & TraceLedger Masters","docId":"ledgers-and-traceledger-masters","unlisted":false},{"type":"link","href":"/delegation-and-access-control","label":"Delegation & Access Control","docId":"delegation-and-access-control","unlisted":false},{"type":"link","href":"/events","label":"Events","docId":"events","unlisted":false},{"type":"link","href":"/signing-reference","label":"Signing Reference","docId":"signing-reference","unlisted":false},{"type":"link","href":"/resolver","label":"Resolver","docId":"resolver","unlisted":false},{"type":"link","href":"/webhooks","label":"Webhooks","docId":"webhooks","unlisted":false},{"type":"link","href":"/integrity-verification","label":"Integrity Verification","docId":"integrity-verification","unlisted":false},{"type":"link","href":"/error-handling","label":"Error Handling","docId":"error-handling","unlisted":false}],"collapsible":true},{"type":"category","label":"API Reference","collapsed":false,"items":[{"type":"link","href":"/public-api-reference","label":"Public API Reference","docId":"public-api-reference","unlisted":false}],"collapsible":true},{"type":"category","label":"Network & Verification","collapsed":false,"items":[{"type":"link","href":"/network-model","label":"Network Model","docId":"network-model","unlisted":false},{"type":"link","href":"/cross-party-verification","label":"Cross-Party Verification","docId":"cross-party-verification","unlisted":false}],"collapsible":true},{"type":"category","label":"Guides","collapsed":false,"items":[{"type":"link","href":"/launchable-integration-flows","label":"Integration Flows","docId":"launchable-integration-flows","unlisted":false},{"type":"link","href":"/e2e-full-sandbox","label":"Full Network Sandbox (e2e_full)","docId":"e2e-full-sandbox","unlisted":false}],"collapsible":true},{"type":"category","label":"Production","collapsed":true,"items":[{"type":"link","href":"/developer-onboarding-checklist","label":"Developer Onboarding","docId":"developer-onboarding-checklist","unlisted":false},{"type":"link","href":"/production-deployment-checklist","label":"Production Deployment","docId":"production-deployment-checklist","unlisted":false},{"type":"link","href":"/faq","label":"FAQ","docId":"faq","unlisted":false}],"collapsible":true}]},"docs":{"actors-and-public-identity":{"id":"actors-and-public-identity","title":"Actors and Public Identity","description":"An actor is the unit of identity in the Genesis X-1 protocol. Not a user account. Not a session. An actor is a permanent, addressable identity with a cryptographic signing key \u2014 the entity that authorizes events, holds access grants, and appears in the immutable record of every action taken under its credentials.","sidebar":"docsSidebar"},"authentication-and-identity":{"id":"authentication-and-identity","title":"Authentication and Identity","description":"Every request to Genesis X-1 is scoped to a specific actor. There is no anonymous access to authenticated surfaces. There is no shared credential. Every operation is attributed to the actor whose credential authorized it.","sidebar":"docsSidebar"},"core-concepts":{"id":"core-concepts","title":"Core Concepts","description":"Genesis X-1 defines a precise protocol vocabulary. These terms carry exact meanings within the protocol. Implementations must use them as specified.","sidebar":"docsSidebar"},"cross-party-verification":{"id":"cross-party-verification","title":"Cross-Party Verification","description":"Genesis X-1 supports independent Ed25519 signature verification by any party that has been granted access to a ledger. No trust in the server is required \u2014 verification uses only the actor\'s public key and the event data returned by the API.","sidebar":"docsSidebar"},"delegation-and-access-control":{"id":"delegation-and-access-control","title":"Delegation and Access Control","description":"Access in Genesis X-1 is not assumed. It is declared, signed, and recorded.","sidebar":"docsSidebar"},"developer-onboarding-checklist":{"id":"developer-onboarding-checklist","title":"Developer Onboarding Checklist","description":"- Obtain a sandbox and production API key through POST /developer/register.","sidebar":"docsSidebar"},"e2e-full-sandbox":{"id":"e2e-full-sandbox","title":"Full Network Sandbox","description":"The Genesis X-1 sandbox simulates a complete 5-party agricultural supply-chain trade on the live production API \u2014 from actor registration through to cross-party Ed25519 verification.","sidebar":"docsSidebar"},"entity-and-root-ledger-model":{"id":"entity-and-root-ledger-model","title":"Entity and Root Ledger Model","description":"Entity","sidebar":"docsSidebar"},"error-handling":{"id":"error-handling","title":"Error Handling","description":"Public Error Envelope","sidebar":"docsSidebar"},"events":{"id":"events","title":"Events","description":"Events are not database records. They are independently verifiable facts with continuity.","sidebar":"docsSidebar"},"faq":{"id":"faq","title":"FAQ","description":"Is Genesis X-1 a blockchain?","sidebar":"docsSidebar"},"integrity-verification":{"id":"integrity-verification","title":"Integrity Verification","description":"Integrity is not a feature. It is a mathematical property of the ledger.","sidebar":"docsSidebar"},"launchable-integration-flows":{"id":"launchable-integration-flows","title":"Launchable Integration Flows","description":"Buyer Opens a Ledger with a Supplier","sidebar":"docsSidebar"},"ledgers-and-traceledger-masters":{"id":"ledgers-and-traceledger-masters","title":"Ledgers and TraceLedger Masters","description":"Economic systems do not fail at value. They fail at continuity.","sidebar":"docsSidebar"},"network-model":{"id":"network-model","title":"Network Model","description":"A Genesis X-1 deployment is a multi-party protocol network. Each participant class operates an independent organizational boundary. Trust between parties is not assumed \u2014 it is established through signed delegation grants, enforced at the ledger boundary, and independently verifiable by any permissioned party.","sidebar":"docsSidebar"},"organization-onboarding":{"id":"organization-onboarding","title":"Organization Onboarding","description":"An organization is the registered business entity on the Genesis X-1 network. Every organization has an actor \u2014 the identity unit that authenticates requests and signs events. The organization provides the business continuity anchor. The actor provides the cryptographic identity.","sidebar":"docsSidebar"},"product-overview":{"id":"product-overview","title":"Product Overview","description":"Genesis X-1 is the verifiable state layer for inter-organizational trade networks.","sidebar":"docsSidebar"},"production-deployment-checklist":{"id":"production-deployment-checklist","title":"Production Deployment Checklist","description":"- Auth configured: all production calls use valid API keys or the correct explicit actor identity path.","sidebar":"docsSidebar"},"public-api-reference":{"id":"public-api-reference","title":"Public API Reference","description":"The public base path is /v1.","sidebar":"docsSidebar"},"quickstart":{"id":"quickstart","title":"Quickstart","description":"This quickstart creates two production actors, onboards both organizations, opens an order ledger, creates a traceledger master, appends a signed event, reads the resulting chain, verifies integrity, and registers a webhook.","sidebar":"docsSidebar"},"README":{"id":"README","title":"Genesis X-1 \u2014 Developer Documentation","description":"One Transaction. One State."},"resolver":{"id":"resolver","title":"Resolver","description":"Public Resolver Surface","sidebar":"docsSidebar"},"signing-reference":{"id":"signing-reference","title":"Signing Reference","description":"Every business event appended to Genesis X-1 carries an Ed25519 actor signature. This signature is what makes the event independently verifiable \u2014 any party with the actor\'s public key can confirm who authorized the event, what was authorized, and that nothing was changed after signing.","sidebar":"docsSidebar"},"webhooks":{"id":"webhooks","title":"Webhooks","description":"Subscription Model","sidebar":"docsSidebar"}}}}')}}]);